import{_ as l,o as e,c as i,a0 as t}from"./chunks/framework.CWk8AOcY.js";const b=JSON.parse('{"title":"什么是安全边界与隔离模型","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/security-boundary.md","filePath":"zh/guide/concepts/security-boundary.md"}'),o={name:"guide/concepts/security-boundary.md"};function r(u,a,n,h,p,s){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="什么是安全边界与隔离模型" tabindex="-1">什么是安全边界与隔离模型 <a class="header-anchor" href="#什么是安全边界与隔离模型" aria-label="Permalink to &quot;什么是安全边界与隔离模型&quot;">​</a></h1><h2 id="一句话定义" tabindex="-1">一句话定义 <a class="header-anchor" href="#一句话定义" aria-label="Permalink to &quot;一句话定义&quot;">​</a></h2><p>CubeSandbox 的核心价值，不只是“把代码跑起来”，而是：</p><blockquote><p><strong>把不可信、不可预测、可能带有攻击性的工作负载，放进一个边界清晰、可控、可回收的执行环境里运行。</strong></p></blockquote><p>因此，安全边界与隔离模型不是附属主题，而是理解 CubeSandbox 的最后一块地基。</p><h2 id="为什么必须先讲-边界-再讲-安全" tabindex="-1">为什么必须先讲“边界”，再讲“安全” <a class="header-anchor" href="#为什么必须先讲-边界-再讲-安全" aria-label="Permalink to &quot;为什么必须先讲“边界”，再讲“安全”&quot;">​</a></h2><p>很多系统谈安全时会直接列特性：</p><ul><li>独立内核</li><li>eBPF 网络隔离</li><li>API 鉴权</li><li>TLS</li><li>权限控制</li></ul><p>这些都重要，但如果不先问一个问题，就永远看不清：</p><blockquote><p><strong>CubeSandbox 试图保护谁，防谁，边界画在哪里？</strong></p></blockquote><p>安全从来不是抽象美德，而是边界管理。</p><p>理解 CubeSandbox 的安全，必须先回答三个问题：</p><ol><li>哪些东西必须彼此隔离？</li><li>哪些东西必须可以被平台控制？</li><li>哪些风险不在这个系统单独兜底的范围内？</li></ol><h2 id="cubesandbox-最核心的安全命题" tabindex="-1">CubeSandbox 最核心的安全命题 <a class="header-anchor" href="#cubesandbox-最核心的安全命题" aria-label="Permalink to &quot;CubeSandbox 最核心的安全命题&quot;">​</a></h2><p>CubeSandbox 面对的典型场景是：</p><ul><li>用户代码不可信</li><li>Agent 行为不可完全预测</li><li>工作负载可能主动发起网络访问</li><li>实例可能运行复杂用户态程序甚至服务</li></ul><p>因此它最核心的安全命题是：</p><blockquote><p><strong>如何让一个实例中的风险，不轻易溢出到宿主机、其它实例和整个平台。</strong></p></blockquote><p>这和普通“把服务部署起来”的平台诉求有本质不同。</p><h2 id="cubesandbox-的边界不是单一边界-而是多层边界" tabindex="-1">CubeSandbox 的边界不是单一边界，而是多层边界 <a class="header-anchor" href="#cubesandbox-的边界不是单一边界-而是多层边界" aria-label="Permalink to &quot;CubeSandbox 的边界不是单一边界，而是多层边界&quot;">​</a></h2><p>把 CubeSandbox 的安全边界理解成一条线是错误的。它更像是多层叠加的边界模型。</p><h3 id="_1-执行边界" tabindex="-1">1. 执行边界 <a class="header-anchor" href="#_1-执行边界" aria-label="Permalink to &quot;1. 执行边界&quot;">​</a></h3><p>执行边界解决的是：</p><ul><li>实例里的进程是否与宿主机共享内核执行上下文</li><li>一个实例里的崩溃或攻击是否会直接影响其它实例</li></ul><p>CubeSandbox 选择以独立 Guest 内核和 MicroVM 作为这一层的核心基础。</p><h3 id="_2-状态边界" tabindex="-1">2. 状态边界 <a class="header-anchor" href="#_2-状态边界" aria-label="Permalink to &quot;2. 状态边界&quot;">​</a></h3><p>状态边界解决的是：</p><ul><li>一个实例的运行状态是否会污染另一个实例</li><li>实例写入的数据是否会回写到模板母版</li><li>回收后差异状态是否会残留</li></ul><p>这层依赖模板 / 可写层 / 生命周期回收等机制共同成立。</p><h3 id="_3-网络边界" tabindex="-1">3. 网络边界 <a class="header-anchor" href="#_3-网络边界" aria-label="Permalink to &quot;3. 网络边界&quot;">​</a></h3><p>网络边界解决的是：</p><ul><li>Sandbox 是否能随意访问内网与宿主机</li><li>一个实例的网络行为是否天然暴露给另一个实例</li><li>是否能按实例粒度控制出站与入站能力</li></ul><p>这层由 CubeVS、节点本地网络编排、端口暴露与代理路由共同构成。</p><h3 id="_4-平台控制边界" tabindex="-1">4. 平台控制边界 <a class="header-anchor" href="#_4-平台控制边界" aria-label="Permalink to &quot;4. 平台控制边界&quot;">​</a></h3><p>平台控制边界解决的是：</p><ul><li>谁能创建实例</li><li>谁能访问 API</li><li>谁能暴露服务</li><li>谁能修改模板与运行参数</li></ul><p>这层更多落在控制面、鉴权、配置和运维治理之上。</p><h2 id="为什么-独立-guest-内核-是最关键的安全语义之一" tabindex="-1">为什么“独立 Guest 内核”是最关键的安全语义之一 <a class="header-anchor" href="#为什么-独立-guest-内核-是最关键的安全语义之一" aria-label="Permalink to &quot;为什么“独立 Guest 内核”是最关键的安全语义之一&quot;">​</a></h2><p>CubeSandbox 和普通共享宿主机内核容器模型最大的安全区别，往往就体现在这里。</p><h3 id="共享内核模型的问题" tabindex="-1">共享内核模型的问题 <a class="header-anchor" href="#共享内核模型的问题" aria-label="Permalink to &quot;共享内核模型的问题&quot;">​</a></h3><p>当多个不可信工作负载共享同一个宿主机内核时，平台必须假设：</p><ul><li>内核攻击面是共享的</li><li>内核级漏洞一旦被利用，可能直接影响宿主机或其它租户</li><li>隔离主要依赖 namespace / cgroup / seccomp 等防线组合</li></ul><p>这套模型在很多场景有效，但面对“执行任意用户代码”的 Agent 场景时，压力会显著增大。</p><h3 id="独立-guest-内核带来的变化" tabindex="-1">独立 Guest 内核带来的变化 <a class="header-anchor" href="#独立-guest-内核带来的变化" aria-label="Permalink to &quot;独立 Guest 内核带来的变化&quot;">​</a></h3><p>当每个 Sandbox 都运行在独立 Guest 内核里，风险面被重新切分：</p><ul><li>实例内部问题首先被限制在 Guest 边界内</li><li>不同实例之间不再天然共享同一内核上下文</li><li>平台对“容器逃逸即宿主失守”的担忧显著下降</li></ul><p>这并不意味着安全问题消失，而是意味着：</p><blockquote><p><strong>最关键的一层隔离边界被前移到了更靠近实例的位置。</strong></p></blockquote><h2 id="网络隔离为什么是安全模型的第二根支柱" tabindex="-1">网络隔离为什么是安全模型的第二根支柱 <a class="header-anchor" href="#网络隔离为什么是安全模型的第二根支柱" aria-label="Permalink to &quot;网络隔离为什么是安全模型的第二根支柱&quot;">​</a></h2><p>仅有运行边界还不够。</p><p>即便实例之间在执行上下文上隔离，如果网络上仍能彼此自由探测、横向访问宿主机或私网，那么平台整体风险仍然很高。</p><p>因此 CubeSandbox 的网络能力不只是“连接能力”，更是安全能力：</p><ul><li>默认阻断敏感地址空间访问</li><li>按实例施加出站策略</li><li>按平台元数据决定哪些入口可暴露</li><li>通过节点网络平面实现细粒度隔离</li></ul><p>对于不可信代码执行平台来说，这一点和独立 Guest 内核同等重要。</p><h2 id="为什么-template-与-snapshot-也属于安全模型的一部分" tabindex="-1">为什么 Template 与 Snapshot 也属于安全模型的一部分 <a class="header-anchor" href="#为什么-template-与-snapshot-也属于安全模型的一部分" aria-label="Permalink to &quot;为什么 Template 与 Snapshot 也属于安全模型的一部分&quot;">​</a></h2><p>这听起来可能有点反直觉。</p><p>Template、Snapshot 往往被看成性能概念，但它们也影响安全边界。</p><h3 id="template-影响基础环境一致性" tabindex="-1">Template 影响基础环境一致性 <a class="header-anchor" href="#template-影响基础环境一致性" aria-label="Permalink to &quot;Template 影响基础环境一致性&quot;">​</a></h3><p>如果模板边界不清晰，就容易出现：</p><ul><li>母版被实例污染</li><li>不同实例起点不一致</li><li>难以判断问题源于模板还是实例运行期</li></ul><h3 id="snapshot-影响状态复用边界" tabindex="-1">Snapshot 影响状态复用边界 <a class="header-anchor" href="#snapshot-影响状态复用边界" aria-label="Permalink to &quot;Snapshot 影响状态复用边界&quot;">​</a></h3><p>如果系统不能清楚地区分“可共享基础状态”和“实例私有差异状态”，就可能出现不应共享的状态被复用的问题。</p><p>所以：</p><ul><li>性能优化必须建立在严格边界之上</li><li>快照复用不能以实例私有状态泄漏为代价</li></ul><h2 id="平台信任模型-谁被默认信任-谁不被默认信任" tabindex="-1">平台信任模型：谁被默认信任，谁不被默认信任 <a class="header-anchor" href="#平台信任模型-谁被默认信任-谁不被默认信任" aria-label="Permalink to &quot;平台信任模型：谁被默认信任，谁不被默认信任&quot;">​</a></h2><p>理解安全边界时，必须明确系统的信任分层。</p><h3 id="一般会被更高信任的部分" tabindex="-1">一般会被更高信任的部分 <a class="header-anchor" href="#一般会被更高信任的部分" aria-label="Permalink to &quot;一般会被更高信任的部分&quot;">​</a></h3><ul><li>控制面组件</li><li>节点宿主机与平台运维面</li><li>经过治理的模板与平台配置</li><li>平台入口与鉴权逻辑</li></ul><h3 id="不应被默认完全信任的部分" tabindex="-1">不应被默认完全信任的部分 <a class="header-anchor" href="#不应被默认完全信任的部分" aria-label="Permalink to &quot;不应被默认完全信任的部分&quot;">​</a></h3><ul><li>Sandbox 内部执行的用户代码</li><li>Agent 生成的命令、脚本、下载内容</li><li>Guest 内部动态运行结果</li><li>Sandbox 对外部世界发起的网络行为</li></ul><p>CubeSandbox 的整体设计，正是围绕这个信任分层来构建的。</p><h2 id="平台安全-不等于-用户代码安全" tabindex="-1">“平台安全”不等于“用户代码安全” <a class="header-anchor" href="#平台安全-不等于-用户代码安全" aria-label="Permalink to &quot;“平台安全”不等于“用户代码安全”&quot;">​</a></h2><p>这是另一个必须说透的点。</p><p>CubeSandbox 的目标是：</p><ul><li>限制不可信代码对平台和邻居的伤害范围</li><li>给不可信代码提供受控执行空间</li></ul><p>它不等于：</p><ul><li>自动审计所有用户代码逻辑是否安全</li><li>自动阻止一切业务层漏洞</li><li>自动保证 Guest 内应用本身没有漏洞</li></ul><p>也就是说，CubeSandbox 提供的是 <strong>基础执行边界安全</strong>，而不是替代应用安全、供应链安全或业务安全本身。</p><h2 id="安全边界内外各自承担什么责任" tabindex="-1">安全边界内外各自承担什么责任 <a class="header-anchor" href="#安全边界内外各自承担什么责任" aria-label="Permalink to &quot;安全边界内外各自承担什么责任&quot;">​</a></h2><h3 id="平台侧责任" tabindex="-1">平台侧责任 <a class="header-anchor" href="#平台侧责任" aria-label="Permalink to &quot;平台侧责任&quot;">​</a></h3><p>平台通常要保证：</p><ul><li>实例边界足够强</li><li>网络路径受控</li><li>模板与实例状态分层清晰</li><li>API、配置和暴露入口有治理能力</li><li>节点回收和清理不留下明显残留风险</li></ul><h3 id="使用方责任" tabindex="-1">使用方责任 <a class="header-anchor" href="#使用方责任" aria-label="Permalink to &quot;使用方责任&quot;">​</a></h3><p>使用方仍然需要保证：</p><ul><li>选择合适模板</li><li>配置合理的网络开放范围</li><li>不把敏感密钥无节制地注入实例</li><li>对业务级访问控制与代码来源做治理</li><li>对 Guest 内应用本身的安全负责</li></ul><p>安全永远是分层责任，而不是一键托管。</p><h2 id="为什么-可回收-也是安全能力" tabindex="-1">为什么“可回收”也是安全能力 <a class="header-anchor" href="#为什么-可回收-也是安全能力" aria-label="Permalink to &quot;为什么“可回收”也是安全能力&quot;">​</a></h2><p>很多人把安全只理解成“防攻击”。</p><p>但对于高频创建销毁的平台，<strong>回收正确性</strong> 本身就是安全能力。</p><p>如果一个 Sandbox 销毁后：</p><ul><li>网络映射没释放</li><li>可写状态没清干净</li><li>本地临时目录残留</li><li>元数据仍然可误引用</li></ul><p>那边界就并没有真正结束。</p><p>因此回收不是运维附属动作，而是安全边界闭环的一部分。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><h3 id="误解一-有独立-guest-内核就等于绝对安全" tabindex="-1">误解一：有独立 Guest 内核就等于绝对安全 <a class="header-anchor" href="#误解一-有独立-guest-内核就等于绝对安全" aria-label="Permalink to &quot;误解一：有独立 Guest 内核就等于绝对安全&quot;">​</a></h3><p>不对。</p><p>独立 Guest 内核显著增强边界，但平台安全仍然依赖：</p><ul><li>节点配置</li><li>网络策略</li><li>控制面鉴权</li><li>模板治理</li><li>运行时实现质量</li></ul><h3 id="误解二-网络隔离只是-锦上添花" tabindex="-1">误解二：网络隔离只是“锦上添花” <a class="header-anchor" href="#误解二-网络隔离只是-锦上添花" aria-label="Permalink to &quot;误解二：网络隔离只是“锦上添花”&quot;">​</a></h3><p>不对。</p><p>对执行不可信代码的平台来说，网络往往是攻击面和数据外流面。没有网络边界，安全模型是不完整的。</p><h3 id="误解三-sandbox-里发生的事只要不逃逸-就与平台无关" tabindex="-1">误解三：Sandbox 里发生的事只要不逃逸，就与平台无关 <a class="header-anchor" href="#误解三-sandbox-里发生的事只要不逃逸-就与平台无关" aria-label="Permalink to &quot;误解三：Sandbox 里发生的事只要不逃逸，就与平台无关&quot;">​</a></h3><p>不对。</p><p>即使不发生宿主逃逸，实例内资源滥用、恶意出网、异常暴露服务、残留状态污染等，仍然会影响平台安全与治理。</p><h2 id="你应该记住的核心判断" tabindex="-1">你应该记住的核心判断 <a class="header-anchor" href="#你应该记住的核心判断" aria-label="Permalink to &quot;你应该记住的核心判断&quot;">​</a></h2><p>如果只记一句话，请记住：</p><blockquote><p>CubeSandbox 的安全不是单点能力，而是“独立 Guest 内核 + 分层状态模型 + 实例级网络控制 + 平台治理”的组合结果。</p></blockquote><h2 id="和相关文档的关系" tabindex="-1">和相关文档的关系 <a class="header-anchor" href="#和相关文档的关系" aria-label="Permalink to &quot;和相关文档的关系&quot;">​</a></h2><ul><li>想看实例对象： <a href="./sandbox.html">什么是 Sandbox</a></li><li>想看运行边界来源： <a href="./microvm-runtime-guest.html">什么是 MicroVM、Runtime 与 Guest</a></li><li>想看网络边界： <a href="./network-exposure.html">什么是网络、暴露端口与访问路径</a></li><li>想看鉴权： <a href="./../authentication.html">鉴权</a></li><li>想看运维安全与排障： <a href="./../ops-manual/05-logs-health-and-troubleshooting.html">日志、健康检查与排障</a></li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>到这里，CubeSandbox 最核心的概念链条就完整了：</p><ul><li>Sandbox 是交付对象</li><li>Template 是母版对象</li><li>MicroVM / Runtime / Guest 是运行模型</li><li>Snapshot 是性能复用机制</li><li>Node / Cluster / Scheduling 是平台扩展模型</li><li>Network / Exposure 是可达性与网络边界模型</li><li>Filesystem / Writable Layer 是状态分层模型</li><li>Security Boundary 是这些能力最终共同服务的目标</li></ul><p>如果你已经理解这些概念，再去看快速开始、模板制作、运维手册或源码，视角会完全不同。</p>',113)])])}const c=l(o,[["render",r]]);export{b as __pageData,c as default};
